class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val=val; self.left=left; self.right=right

def morris_inorder(root):
    result = []
    curr   = root
    while curr:
        if not curr.left:
            result.append(curr.val)
            curr = curr.right
        else:
            # Find in-order predecessor (rightmost in left subtree)
            pre = curr.left
            while pre.right and pre.right is not curr:
                pre = pre.right
            if pre.right is None:
                # Thread: predecessor's right -> curr
                pre.right = curr
                curr      = ___________   # descend into left subtree
            else:
                # Thread already set — we've returned; unthread and process
                pre.right = ___________   # remove thread
                result.append(curr.val)
                curr = curr.right
    return result
